def min_rebuild_time(n, times, edges, changed):
    from collections import deque, defaultdict

    hard_forward = defaultdict(list)
    hard_reverse = defaultdict(list)
    all_forward = defaultdict(list)

    for a, b, t in edges:
        all_forward[b].append(a)
        if t == 0:
            hard_forward[b].append(a)
            hard_reverse[a].append(b)

    # Cycle detection on hard dependencies using Kahn's algorithm
    hard_in_degree = [0] * n
    for a, b, t in edges:
        if t == 0:
            hard_in_degree[a] += 1

    q = deque()
    for i in range(n):
        if hard_in_degree[i] == 0:
            q.append(i)

    topo = []
    temp_deg = hard_in_degree[:]
    while q:
        node = q.popleft()
        topo.append(node)
        for dep in hard_forward[node]:
            temp_deg[dep] -= 1
            if temp_deg[dep] == 0:
                q.append(dep)

    if len(topo) != n:
        return -1

    # Invalidation propagation through all edges (hard + soft)
    invalidated = set(changed)
    bfs = deque(changed)
    while bfs:
        node = bfs.popleft()
        for dependent in all_forward[node]:
            if dependent not in invalidated:
                invalidated.add(dependent)
                bfs.append(dependent)

    if not invalidated:
        return 0

    # Critical path computation using hard edges only
    earliest_completion = {}
    for node in topo:
        if node not in invalidated:
            continue
        earliest_start = 0
        for dep in hard_reverse[node]:
            if dep in earliest_completion:
                earliest_start = max(earliest_start, earliest_completion[dep])
        earliest_completion[node] = earliest_start + times[node]

    return max(earliest_completion.values())

