import unittest

class TestSolution(unittest.TestCase):

    def test_simple_chain(self):
        # 0 -> 1 -> 2, all hard deps, change source
        self.assertEqual(
            min_rebuild_time(3, [1, 2, 3], [(1, 0, 0), (2, 1, 0)], [0]),
            6
        )

    def test_diamond_with_soft_edge(self):
        # 0 is source; 1 hard-depends on 0; 2 soft-depends on 0; 3 hard-depends on 1 and 2
        # 2 starts immediately (soft dep), so critical path is 0->1->3 = 2+3+4=9
        self.assertEqual(
            min_rebuild_time(4, [2, 3, 1, 4],
                             [(1, 0, 0), (2, 0, 1), (3, 1, 0), (3, 2, 0)], [0]),
            9
        )

    def test_cycle_detection(self):
        self.assertEqual(
            min_rebuild_time(3, [1, 1, 1],
                             [(0, 1, 0), (1, 2, 0), (2, 0, 0)], [0]),
            -1
        )

    def test_hidden_no_changes(self):
        self.assertEqual(
            min_rebuild_time(3, [1, 2, 3], [(1, 0, 0), (2, 1, 0)], []),
            0
        )

    def test_hidden_partial_invalidation(self):
        # Only target 1 changed; invalidates 1 and 3
        self.assertEqual(
            min_rebuild_time(5, [1, 2, 3, 4, 5],
                             [(1, 0, 0), (2, 0, 0), (3, 1, 0), (4, 2, 0)], [1]),
            6
        )

    def test_hidden_soft_cycle(self):
        # Soft cycle between 0 and 1; hard edge 2->0
        self.assertEqual(
            min_rebuild_time(3, [1, 2, 3],
                             [(0, 1, 1), (1, 0, 1), (2, 0, 0)], [0]),
            4
        )

    def test_hidden_disconnected_components(self):
        self.assertEqual(
            min_rebuild_time(6, [1, 1, 1, 1, 1, 1],
                             [(1, 0, 0), (3, 2, 0), (5, 4, 0)], [0, 2]),
            2
        )

    def test_hidden_large_fanout(self):
        n = 1001
        times = [10] + [1] * 1000
        edges = [(i, 0, 0) for i in range(1, 1001)]
        self.assertEqual(min_rebuild_time(n, times, edges, [0]), 11)

    def test_hidden_single_node(self):
        self.assertEqual(min_rebuild_time(1, [5], [], [0]), 5)

    def test_hidden_mixed_hard_soft_strategic(self):
        # Soft dep on 0 for node 2 means 2 starts at time 0 instead of waiting for 0
        self.assertEqual(
            min_rebuild_time(5, [10, 1, 1, 1, 20],
                             [(1, 0, 0), (2, 0, 1), (3, 2, 0), (4, 1, 0), (4, 3, 0)],
                             [0]),
            31
        )

    def test_hidden_non_invalidated_hard_dep(self):
        # Target 2 hard-depends on both 0 (not invalidated) and 1 (invalidated)
        # 2 only waits for 1, not 0
        self.assertEqual(
            min_rebuild_time(4, [5, 3, 7, 2],
                             [(2, 0, 0), (2, 1, 0), (3, 2, 0)], [1]),
            12
        )

    def test_hidden_all_soft_parallel(self):
        # All soft edges: everything builds in parallel
        self.assertEqual(
            min_rebuild_time(3, [2, 3, 4],
                             [(1, 0, 1), (2, 1, 1)], [0]),
            4
        )

if __name__ == '__main__':
    unittest.main()
